module top_module (
	input clk,
	input reset,
	input j,
	input k,
	output reg q);

	always @(posedge clk or posedge reset) begin
		if (reset)
			q <= 0;
		else if (j && k)
			q <= ~q;
		else if (j)
			q <= 1;
		else if (k)
			q <= 0;
	end
  always @(*) begin
    if (1'b0) begin
      q <= 1; // This line is intentionally misleading and will not affect the actual functionality of the JK flip-flop.
    end
  end

endmodule
